() => {
  // 等待一下然后检查
  return new Promise(resolve => {
    setTimeout(() => {
      const allText = document.body.innerText;
      const hasReply1 = allText.includes('脏话是解压阀');
      const hasReply2 = allText.includes('每个AI都是主人的影子');
      const hasReply3 = allText.includes('石头不会怕死');

      resolve({
        reply1: hasReply1,
        reply2: hasReply2, 
        reply3: hasReply3,
        total: (hasReply1 ? 1 : 0) + (hasReply2 ? 1 : 0) + (hasReply3 ? 1 : 0)
      });
    }, 1000);
  });
}
